def _load_json_file(path: Path) -> dict[str, Any]:
    return json.loads(path.read_text(encoding="utf-8-sig"))


def _resolve_codex_cli() -> str:
    explicit = os.getenv("CODEX_CLI", "").strip().strip('"')
    if explicit:
        return explicit
    for candidate in ("codex", "codex.cmd", "codex.exe", "codex.ps1"):
        found = shutil.which(candidate)
        if found:
            return found
    appdata = os.getenv("APPDATA", "").strip() if os.name == "nt" else ""
    if appdata:
        for name in ("codex.cmd", "codex.exe", "codex.ps1"):
            candidate_path = os.path.join(appdata, "npm", name)
            if os.path.exists(candidate_path):
                return candidate_path
    return ""


def _codex_cli_unavailable_payload(error: str = "") -> dict[str, Any]:
    return {
        "status": "unavailable",
        "verdict": "partial",
        "reason": "codex_cli_unavailable",
        "error": error,
        "next_action": (
            "Install Codex CLI on this OS or set CODEX_CLI to the full executable path. "
            "If Windows PowerShell cannot find codex, run the judge from WSL where codex is on PATH, "
            "or set CODEX_CLI before rerunning the smoke."
        ),
    }


def _codex_exec_args(*, model: str, schema_path: Path) -> list[str] | None:
    codex_cli = _resolve_codex_cli()
    if not codex_cli:
        return None
    return [
        codex_cli,
        "exec",
        "--ephemeral",
        "--sandbox",
        "read-only",
        "--model",
        model,
        "--output-schema",
        str(schema_path),
        "-",
    ]


def _redact_codex_judge_preview(text: str, *, limit: int = 1000) -> str:
    """Keep judge runner diagnostics without echoing private transcript packets."""

    preview = str(text or "")
    for marker in ("Packet:", '"transcript"', '"turns"', '"reply_text"', '"results"', '"user"'):
        if marker in preview:
            preview = preview.split(marker, 1)[0] + "[redacted judge packet]"
            break
    return preview[-limit:]


def _codex_judge_failure_reason(stderr: str = "", stdout: str = "") -> str:
    combined = f"{stderr}\n{stdout}"
    if "requires a newer version of Codex" in combined:
        return "codex_judge_model_requires_newer_codex"
    return "codex_judge_failed"


class FunctionalSubjectCaseTimeout(RuntimeError):
    """Raised when a single Functional Subject trial case exceeds its budget."""


def _case_timeout_supported() -> bool:
    return hasattr(signal, "SIGALRM") and hasattr(signal, "setitimer")


@contextlib.contextmanager
def _functional_subject_case_timeout(timeout_seconds: int | None):
    seconds = max(0, int(timeout_seconds or 0))
    if seconds <= 0 or not _case_timeout_supported():
        yield
        return

    previous_handler = signal.getsignal(signal.SIGALRM)

    def _handle_timeout(_signum, _frame):
        raise FunctionalSubjectCaseTimeout(f"functional subject case exceeded {seconds}s")

    signal.signal(signal.SIGALRM, _handle_timeout)
    signal.setitimer(signal.ITIMER_REAL, float(seconds))
    try:
        yield
    finally:
        signal.setitimer(signal.ITIMER_REAL, 0.0)
        signal.signal(signal.SIGALRM, previous_handler)


def _shell_command_from_args(args: list[str]) -> str:
    if os.name == "nt":
        return subprocess.list2cmdline(args)
    return shlex.join(args)

